    int *x = (int *)a;
    int *y = (int *)b;
    return x[0] - y[0];
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int baskets[N][2];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &baskets[i][0], &baskets[i][1]);
        }
        int min_side = INT_MAX;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                int side = abs(baskets[i][0] - baskets[j][0]);
                if (side > min_side) continue;
                for (int k = 0; k < N; k++) {
                    if (k == i || k == j) continue;
                    if (abs(baskets[k][0] - baskets[i][0]) <= side && abs(baskets[k][1] - baskets[i][1]) <= side) {
                        min_side = side;
                    }
                }
            }
        }
        printf("%d\n", min_side);
    }
    return 0;
}

