import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[][] baskets = new int[N][2];
            for (int i = 0; i < N; i++) {
                baskets[i][0] = sc.nextInt();
                baskets[i][1] = sc.nextInt();
            }
            int min_side = Integer.MAX_VALUE;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    int side = Math.abs(baskets[i][0] - baskets[j][0]);
                    if (side > min_side) continue;
                    for (int k = 0; k < N; k++) {
                        if (k == i || k == j) continue;
                        if (Math.abs(baskets[k][0] - baskets[i][0]) <= side && Math.abs(baskets[k][1] - baskets[i][1]) <= side) {
                            min_side = side;
                        }
                    }
                }
            }
            System.out.println(min_side);
        }
    }
}

